  "req.status.met": { en: "Met", nl: "Voldaan", de: "Erfüllt", fr: "Satisfait", es: "Cumplido" },
  "req.status.by-design": { en: "By design", nl: "Bewust ontworpen", de: "Bewusst so", fr: "Par conception", es: "Por diseño" },
